mapper.select:

SELECT
	 RESULT_RAW_DATA as resultRawData
FROM TBINTRFCDEPLOYHISTHS
WHERE INTRFC_ID = #{intrfcId, jdbcType = VARCHAR} 
AND DEPLOY_VERSION = #{deployVersion, jdbcType = NUMERIC}
AND DEPLOY_DTTM = #{deployDttm, jdbcType = VARCHAR}
AND DEPLOY_RESULT_CD = #{deployResultCd, jdbcType = VARCHAR}

mapper.insert:
	INSERT INTO TBINTRFCDEPLOYHISTHS (
		 INTRFC_ID		
		,DEPLOY_VERSION		
		,DEPLOY_DTTM		
		,DEPLOY_SYS_CD		
		,DEPLOY_RESULT_CD		
		,RAW_DATA	
		,RESULT_RAW_DATA	
	) VALUES (
		 #{intrfcId, jdbcType = VARCHAR}
 		,#{deployVersion, jdbcType = NUMERIC}
 		,#{deployDttm, jdbcType = VARCHAR}
 		,#{deploySysCd, jdbcType = VARCHAR}
 		,#{deployResultCd, jdbcType = VARCHAR}
 		,#{rawData}
 		,#{resultRawData}
  	)

mapper.update:
	UPDATE TBINTRFCDEPLOYHISTHS 
	SET
 		DEPLOY_VERSION = #{deployVersion, jdbcType = NUMERIC}		
  		,DEPLOY_DTTM = #{deployDttm, jdbcType = VARCHAR}		
  		,DEPLOY_SYS_CD = #{deploySysCd, jdbcType = VARCHAR}		
  		,DEPLOY_RESULT_CD = #{deployResultCd, jdbcType = VARCHAR}		
  		,RAW_DATA = #{rawData}		
  		,RESULT_RAW_DATA = #{resultRawData}
   	WHERE INTRFC_ID = #{intrfcId, jdbcType = VARCHAR}
